const fs = require('fs');
const path = require('path');

const projectRoot = path.resolve(__dirname, '..');
const migrationsDir = path.join(projectRoot, 'supabase', 'migrations');
const outputDir = path.join(projectRoot, 'supabase', 'bootstrap');
const outputFile = path.join(outputDir, 'full-setup.sql');

function getMigrationFiles() {
  if (!fs.existsSync(migrationsDir)) {
    throw new Error('supabase/migrations does not exist.');
  }

  return fs
    .readdirSync(migrationsDir)
    .filter((fileName) => fileName.endsWith('.sql'))
    .sort();
}

function buildBundle() {
  const migrationFiles = getMigrationFiles();

  if (migrationFiles.length === 0) {
    throw new Error('No migration files were found.');
  }

  const headerLines = [
    '-- SideRoom Supabase Full Setup Bundle',
    '-- Generated automatically by scripts/build-supabase-bundle.js',
    '-- Do not edit this file by hand. Edit the ordered files in supabase/migrations instead.',
    '--',
    '-- Migration order included in this bundle:',
    ...migrationFiles.map((fileName, index) => `-- ${index + 1}. ${fileName}`),
    '',
  ];

  const sections = migrationFiles.map((fileName) => {
    const filePath = path.join(migrationsDir, fileName);
    const sql = fs.readFileSync(filePath, 'utf8').trimEnd();

    return [
      `-- BEGIN MIGRATION: ${fileName}`,
      sql,
      `-- END MIGRATION: ${fileName}`,
      '',
    ].join('\n');
  });

  return `${headerLines.join('\n')}\n${sections.join('\n')}`;
}

function main() {
  const bundle = buildBundle();

  fs.mkdirSync(outputDir, { recursive: true });
  fs.writeFileSync(outputFile, bundle, 'utf8');

  console.log(`Wrote ${path.relative(projectRoot, outputFile)}`);
}

main();
